const input = {{KinSvarmo Job Started}};
const payload = input?.payload ?? input ?? {};
if (!payload.jobId && !payload.metadata?.jobId) throw new Error('Missing jobId');
if (!payload.agentId && !payload.metadata?.agentId) throw new Error('Missing agentId');
return {
  ok: true,
  jobId: payload.jobId ?? payload.metadata.jobId,
  agentId: payload.agentId ?? payload.metadata.agentId,
  filename: payload.filename ?? payload.metadata?.filename ?? null,
  uploadReference: payload.uploadReference ?? payload.metadata?.uploadReference ?? null
};

const job = {{Validate Job Payload.result}};
console.log('KeeperHub accepted KinSvarmo job', job);
return {
  event: 'keeperhub.job.accepted',
  jobId: job.jobId,
  agentId: job.agentId,
  state: 'running'
};

const job = {{Validate Job Payload.result}};
console.log('KeeperHub workflow completed for KinSvarmo job', job.jobId);
return {
  event: 'keeperhub.execution.completed',
  jobId: job.jobId,
  agentId: job.agentId,
  state: 'completed'
};
